defmodule Webhooks.WebhookController do
  use WebhooksWeb, :controller

  plug :fetch_session_token
  plug :verify_access

  alias Webhooks.Api.Httpoison
  def call(conn, params) when is_list(params["targetUrl"]) do
    url = params["targetUrl"]

    result = Httpoison.get(url)
    case result do
      {:ok, %{"content" => content}} ->
        conn
        |> put_resp_header("Content-Type", "application/json")
        |> send_resp(200, content)

      {:error} ->
        send_response(conn, 418) # I'm a teapot
    end
  rescue
    error in _ ->
      Logger.info(error) 
      conn
          |> put_status(503) 
          |> send_resp(503, "")
  end

  defp fetch_session_token do
    {token} = :jwt.decode(:SystemToken.get())

    with {:ok, token} <- :crypto.hmac("hs256", "1234", token),
         {:ok, _} <- JOSE.JWS.verify(token) ->
          {:continue, token}
        else
      {:error} ->
        conn
            |> put_status(:unauthorized) 
            |> put_resp_header("WWW-Authenticate", "\"Basic\"" )
            |> send_resp(401, "")
    end
  end

  defp verify_access(%{token: session_token}, %{token: access_token}) when session_token != access_token do 
    conn
        |> put_status(:unauthorized) 
        |> put_resp_header("WWW-Authenticate", "\"Basic\"" )
        |> send_resp(401, "")
  end

  defp verify_access(%{token: session_token}, %{token: access_token}) when session_token == access_token do 
    {:continue} 
  end
end